/**
 * Job State Invariant Tests
 *
 * Pure unit tests against the Zustand store.
 * These test the 5 required invariants:
 *   INV-1: No COMPLETED with empty clips
 *   INV-2: Terminal monotonicity (failed/completed cannot be regressed)
 *   INV-5: Error state durability under terminal-failed
 */
import { describe, it, expect, beforeEach } from 'vitest';
import { useJobStore } from '@/stores/job';
import type { Job } from '@/types';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const BASE_JOB: Job = {
  id: 'test-job-001',
  status: 'queued',
  progress: 0,
  clip_count: 3,
  created_at: '2026-02-10T13:00:00Z',
};

const failedJob: Job = {
  ...BASE_JOB,
  status: 'failed',
  error_message: 'Transcription failed: DLQ',
};

const completedJobWithClips: Job = {
  ...BASE_JOB,
  status: 'completed',
  progress: 100,
  completed_at: '2026-02-10T13:10:00Z',
  output: {
    clips: [
      { index: 0, url: '/clips/clip_0.mp4', filename: 'clip_0.mp4' },
      { index: 1, url: '/clips/clip_1.mp4', filename: 'clip_1.mp4' },
    ],
  },
};

const completedJobWithEmptyClips: Job = {
  ...BASE_JOB,
  status: 'completed',
  progress: 100,
  completed_at: '2026-02-10T13:10:00Z',
  output: { clips: [] },
};

const renderingJob: Job = {
  ...BASE_JOB,
  status: 'rendering',
  progress: 60,
  current_step: 'smart_render',
};

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('Job Store ΓÇö Terminal Monotonicity (INV-2)', () => {
  beforeEach(() => {
    useJobStore.getState().reset();
  });

  it('setJob must not overwrite failed with completed', () => {
    const { setJob } = useJobStore.getState();

    // Establish failed state
    setJob(failedJob);
    expect(useJobStore.getState().job?.status).toBe('failed');

    // Stale REST poll returns completed
    setJob(completedJobWithClips);

    // Must remain failed
    expect(useJobStore.getState().job?.status).toBe('failed');
  });

  it('setJob must not overwrite failed with rendering', () => {
    const { setJob } = useJobStore.getState();

    setJob(failedJob);
    expect(useJobStore.getState().job?.status).toBe('failed');

    // Stale REST poll returns rendering
    setJob(renderingJob);

    expect(useJobStore.getState().job?.status).toBe('failed');
  });

  it('setJob must not overwrite completed with rendering', () => {
    const { setJob } = useJobStore.getState();

    setJob(completedJobWithClips);
    expect(useJobStore.getState().job?.status).toBe('completed');

    // Stale REST poll returns rendering
    setJob(renderingJob);

    expect(useJobStore.getState().job?.status).toBe('completed');
  });

  it('updateJob must not regress from failed to any non-terminal status', () => {
    const { setJob, updateJob } = useJobStore.getState();

    setJob(failedJob);
    expect(useJobStore.getState().job?.status).toBe('failed');

    // Late step_started WS event tries to set rendering
    updateJob({ status: 'rendering', current_step: 'smart_render' });

    expect(useJobStore.getState().job?.status).toBe('failed');
  });

  it('updateJob must not regress from completed to any state', () => {
    const { setJob, updateJob } = useJobStore.getState();

    setJob(completedJobWithClips);
    expect(useJobStore.getState().job?.status).toBe('completed');

    // Late WS event tries to change status
    updateJob({ status: 'rendering' });

    expect(useJobStore.getState().job?.status).toBe('completed');
  });

  it('failed overrides stale completed from REST', () => {
    const { setJob } = useJobStore.getState();

    // Scenario: REST returns completed (stale), then failed arrives
    setJob(completedJobWithClips);
    expect(useJobStore.getState().job?.status).toBe('completed');

    // Failed must override completed (failed is "more terminal")
    setJob(failedJob);
    expect(useJobStore.getState().job?.status).toBe('failed');

    // Now a second stale completed must NOT override failed
    setJob(completedJobWithClips);
    expect(useJobStore.getState().job?.status).toBe('failed');
  });
});

describe('Job Store ΓÇö No COMPLETED with Empty Clips (INV-1)', () => {
  beforeEach(() => {
    useJobStore.getState().reset();
  });

  it('job_completed with empty clips must not set completed', () => {
    const { setJob, updateJob } = useJobStore.getState();

    // Job is in rendering state
    setJob(renderingJob);

    // job_completed handler does: updateJob({ status: 'completed', output: { clips: [] } })
    updateJob({
      status: 'completed',
      progress: 100,
      completed_at: new Date().toISOString(),
      output: { clips: [] },
    });

    // Must NOT be completed ΓÇö should be failed or remain rendering
    expect(useJobStore.getState().job?.status).not.toBe('completed');
  });

  it('job_completed with valid clips sets completed', () => {
    const { setJob, updateJob } = useJobStore.getState();

    setJob(renderingJob);

    updateJob({
      status: 'completed',
      progress: 100,
      completed_at: new Date().toISOString(),
      output: {
        clips: [{ index: 0, url: '/clips/clip_0.mp4', filename: 'clip_0.mp4' }],
      },
    });

    expect(useJobStore.getState().job?.status).toBe('completed');
  });
});

describe('Job Store ΓÇö Error State Durability (INV-5)', () => {
  beforeEach(() => {
    useJobStore.getState().reset();
  });

  it('setJob must not clear error when state is terminal-failed', () => {
    const { setJob, setError } = useJobStore.getState();

    // Establish failed state with an error
    setJob(failedJob);
    setError('Transcription failed: DLQ');

    expect(useJobStore.getState().error).toBe('Transcription failed: DLQ');

    // Stale REST poll calls setJob ΓÇö error must survive
    setJob({ ...renderingJob }); // This should be rejected by terminal guard

    expect(useJobStore.getState().error).toBe('Transcription failed: DLQ');
    expect(useJobStore.getState().job?.status).toBe('failed');
  });
});

/**
 * JobsList Component Display Tests
 *
 * Verifies that the JobsList component correctly distinguishes between
 * requested clip count and actual clips produced for terminal jobs.
 */
import { describe, it, expect } from 'vitest';
import { render, screen } from '@testing-library/react';
import { JobsList } from '@/components/job/JobsList';
import { useJobs } from '@/hooks/useJobs';
import type { Job } from '@/types';

// Mock the useJobs hook
vi.mock('@/hooks/useJobs', () => ({
  useJobs: vi.fn(),
}));

// Mock next/navigation
vi.mock('next/navigation', () => ({
  useRouter: () => ({ push: vi.fn() }),
}));

// Mock framer-motion to render children directly
vi.mock('framer-motion', () => ({
  motion: {
    div: ({ children, ...props }: any) => <div {...props}>{children}</div>,
  },
}));

const BASE_JOB: Job = {
  id: 'display-test-001',
  status: 'queued',
  progress: 0,
  clip_count: 3, // Requested 3 clips
  created_at: new Date().toISOString(),
};

describe('JobsList Component Display (INV-4)', () => {
  it('shows requested clip count for in-progress jobs', () => {
    const job: Job = { ...BASE_JOB, status: 'rendering', progress: 50 };
    (useJobs as any).mockReturnValue({
      items: [job],
      isLoading: false,
      hasMore: false,
      loadMore: vi.fn(),
      error: null,
    });

    render(<JobsList />);

    // Should just show "3 clips"
    expect(screen.getByText('3 clips')).toBeInTheDocument();
  });

  it('shows "0 / N clips" for failed job with no output', () => {
    const job: Job = { ...BASE_JOB, status: 'failed', error_message: 'Failed' };
    (useJobs as any).mockReturnValue({
      items: [job],
      isLoading: false,
      hasMore: false,
      loadMore: vi.fn(),
      error: null,
    });

    render(<JobsList />);

    // Should show "0 / 3 clips"
    expect(screen.getByText('0 / 3 clips')).toBeInTheDocument();
  });

  it('shows "M / N clips" for completed job with M clips', () => {
    const job: Job = {
      ...BASE_JOB,
      status: 'completed',
      progress: 100,
      output: {
        clips: [
          { index: 0, url: 'a.mp4', filename: 'a.mp4' },
          { index: 1, url: 'b.mp4', filename: 'b.mp4' },
        ],
      },
    };
    (useJobs as any).mockReturnValue({
      items: [job],
      isLoading: false,
      hasMore: false,
      loadMore: vi.fn(),
      error: null,
    });

    render(<JobsList />);

    // Should show "2 / 3 clips"
    expect(screen.getByText('2 / 3 clips')).toBeInTheDocument();
  });
});

'use client';

import { ChangeEvent, FormEvent, useCallback, useEffect, useMemo, useState } from 'react';
import { Button } from '@/components/ui';
import {
  onFirebaseAuthChange,
  signInWithFirebase,
  signOutFirebase,
  type FirebaseUser,
} from '@/config/firebase';
import {
  createTemplate,
  deleteTemplate,
  listTemplates,
  normalizeSlug,
  type FirestoreTemplateDoc,
} from '@/services/admin';
import { DEFAULT_FORM_DATA, type TemplateFormData } from '@/types/admin';
import styles from './page.module.css';

function cloneDefaultFormData(): TemplateFormData {
  return {
    slug: '',
    canvas: { ...DEFAULT_FORM_DATA.canvas },
    styles: {
      title_style: { ...DEFAULT_FORM_DATA.styles.title_style },
    },
    logoFile: null,
    logoPreview: null,
  };
}

function getErrorMessage(error: unknown): string {
  if (error instanceof Error && error.message) {
    return error.message;
  }

  return 'Something went wrong. Please try again.';
}

function isPng(file: File): boolean {
  return file.type === 'image/png' || file.name.toLowerCase().endsWith('.png');
}

export default function AdminPage() {
  const [firebaseUser, setFirebaseUser] = useState<FirebaseUser | null>(null);
  const [authReady, setAuthReady] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(false);

  const [formData, setFormData] = useState<TemplateFormData>(() =>
    cloneDefaultFormData()
  );
  const [templates, setTemplates] = useState<FirestoreTemplateDoc[]>([]);
  const [isLoadingTemplates, setIsLoadingTemplates] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  useEffect(() => {
    const unsubscribe = onFirebaseAuthChange(user => {
      setFirebaseUser(user);
      setAuthReady(true);
    });

    return () => {
      unsubscribe();
    };
  }, []);

  useEffect(() => {
    return () => {
      if (formData.logoPreview) {
        URL.revokeObjectURL(formData.logoPreview);
      }
    };
  }, [formData.logoPreview]);

  const loadTemplates = useCallback(async () => {
    if (!firebaseUser) {
      setTemplates([]);
      return;
    }

    setIsLoadingTemplates(true);

    try {
      const docs = await listTemplates();
      setTemplates(docs);
    } catch (loadError) {
      setError(getErrorMessage(loadError));
    } finally {
      setIsLoadingTemplates(false);
    }
  }, [firebaseUser]);

  useEffect(() => {
    if (!firebaseUser) {
      setTemplates([]);
      return;
    }

    void loadTemplates();
  }, [firebaseUser, loadTemplates]);

  const sortedTemplates = useMemo(() => {
    return [...templates].sort((left, right) => {
      const leftLabel = (left.name || left._docId).trim();
      const rightLabel = (right.name || right._docId).trim();

      return leftLabel.localeCompare(rightLabel);
    });
  }, [templates]);

  const handleConnect = async () => {
    setError(null);
    setSuccess(null);
    setIsAuthLoading(true);

    try {
      await signInWithFirebase();
    } catch (connectError) {
      setError(getErrorMessage(connectError));
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleDisconnect = async () => {
    setError(null);
    setSuccess(null);
    setIsAuthLoading(true);

    try {
      await signOutFirebase();
      setTemplates([]);
    } catch (disconnectError) {
      setError(getErrorMessage(disconnectError));
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleSlugChange = (event: ChangeEvent<HTMLInputElement>) => {
    const slug = normalizeSlug(event.target.value);
    setFormData(prev => ({ ...prev, slug }));
  };

  const handleCanvasChange =
    (key: 'width' | 'height') => (event: ChangeEvent<HTMLInputElement>) => {
      const value = Number.parseInt(event.target.value, 10);
      const nextValue = Number.isFinite(value) ? value : 0;

      setFormData(prev => ({
        ...prev,
        canvas: {
          ...prev.canvas,
          [key]: nextValue,
        },
      }));
    };

  const handleColorChange =
    (key: 'bg_fill' | 'fill') => (event: ChangeEvent<HTMLInputElement>) => {
      const value = event.target.value;
      setFormData(prev => ({
        ...prev,
        styles: {
          title_style: {
            ...prev.styles.title_style,
            [key]: value,
          },
        },
      }));
    };

  const handleLogoChange = (event: ChangeEvent<HTMLInputElement>) => {
    const nextFile = event.target.files?.[0] ?? null;

    if (nextFile && !isPng(nextFile)) {
      setError('Logo must be a PNG file.');
      event.target.value = '';
      return;
    }

    setError(null);

    setFormData(prev => {
      if (prev.logoPreview) {
        URL.revokeObjectURL(prev.logoPreview);
      }

      return {
        ...prev,
        logoFile: nextFile,
        logoPreview: nextFile ? URL.createObjectURL(nextFile) : null,
      };
    });
  };

  const resetForm = () => {
    setFormData(prev => {
      if (prev.logoPreview) {
        URL.revokeObjectURL(prev.logoPreview);
      }

      return cloneDefaultFormData();
    });
  };

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setError(null);
    setSuccess(null);

    if (!firebaseUser) {
      setError('Connect Firebase before seeding.');
      return;
    }

    if (!formData.slug) {
      setError('Template key is required.');
      return;
    }

    if (!formData.logoFile) {
      setError('Logo PNG is required.');
      return;
    }

    if (formData.canvas.width <= 0 || formData.canvas.height <= 0) {
      setError('Canvas width and height must be greater than 0.');
      return;
    }

    setIsSubmitting(true);

    try {
      const docId = await createTemplate(formData);
      setSuccess(`Seed completed: ${docId}`);
      resetForm();
      await loadTemplates();
    } catch (submitError) {
      setError(getErrorMessage(submitError));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (docId: string) => {
    const shouldDelete = window.confirm(`Delete template "${docId}"?`);

    if (!shouldDelete) {
      return;
    }

    setError(null);
    setSuccess(null);

    try {
      await deleteTemplate(docId);
      setSuccess(`Deleted: ${docId}`);
      await loadTemplates();
    } catch (deleteError) {
      setError(getErrorMessage(deleteError));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.header}>
        <h1 className={styles.title}>Admin Panel</h1>
        <p className={styles.subtitle}>
          Seed a template in one step: logo, canvas size, title colors.
        </p>
      </div>

      <section className={styles.panel}>
        <div className={styles.panelHeader}>
          <h2>Firebase Access</h2>
        </div>
        <div className={styles.statusRow}>
          {authReady && firebaseUser ? (
            <p className={styles.connected}>Connected as {firebaseUser.email}</p>
          ) : (
            <p className={styles.muted}>Sign in to write Firestore and Storage.</p>
          )}
          {firebaseUser ? (
            <Button
              variant="secondary"
              onClick={handleDisconnect}
              isLoading={isAuthLoading}
            >
              Disconnect
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleConnect}
              isLoading={isAuthLoading}
              disabled={!authReady}
            >
              Connect Firebase
            </Button>
          )}
        </div>
      </section>

      {error && <div className={styles.error}>{error}</div>}
      {success && <div className={styles.success}>{success}</div>}

      <div className={styles.grid}>
        <section className={styles.panel}>
          <div className={styles.panelHeader}>
            <h2>Seed Template</h2>
          </div>
          <form className={styles.form} onSubmit={handleSubmit}>
            <div className={styles.field}>
              <label htmlFor="seed-slug" className={styles.label}>
                Template Key
              </label>
              <input
                id="seed-slug"
                className={styles.input}
                value={formData.slug}
                onChange={handleSlugChange}
                placeholder="kappu-v1"
                autoComplete="off"
                required
              />
              <p className={styles.muted}>Used for Firestore id and storage path.</p>
            </div>

            <div className={styles.twoCol}>
              <div className={styles.field}>
                <label htmlFor="canvas-width" className={styles.label}>
                  Canvas Width
                </label>
                <input
                  id="canvas-width"
                  type="number"
                  min={1}
                  className={styles.input}
                  value={formData.canvas.width}
                  onChange={handleCanvasChange('width')}
                  required
                />
              </div>
              <div className={styles.field}>
                <label htmlFor="canvas-height" className={styles.label}>
                  Canvas Height
                </label>
                <input
                  id="canvas-height"
                  type="number"
                  min={1}
                  className={styles.input}
                  value={formData.canvas.height}
                  onChange={handleCanvasChange('height')}
                  required
                />
              </div>
            </div>

            <div className={styles.twoCol}>
              <div className={styles.field}>
                <label htmlFor="bg-fill" className={styles.label}>
                  Title Background
                </label>
                <input
                  id="bg-fill"
                  type="color"
                  className={styles.colorInput}
                  value={formData.styles.title_style.bg_fill}
                  onChange={handleColorChange('bg_fill')}
                />
              </div>
              <div className={styles.field}>
                <label htmlFor="text-fill" className={styles.label}>
                  Title Text Fill
                </label>
                <input
                  id="text-fill"
                  type="color"
                  className={styles.colorInput}
                  value={formData.styles.title_style.fill}
                  onChange={handleColorChange('fill')}
                />
              </div>
            </div>

            <div className={styles.field}>
              <label htmlFor="logo-file" className={styles.label}>
                Logo PNG
              </label>
              <input
                id="logo-file"
                type="file"
                accept="image/png"
                className={styles.fileInput}
                onChange={handleLogoChange}
                required
              />
              <p className={styles.muted}>
                Uploaded as <code>logo.png</code> to{' '}
                <code>templates/&lt;key&gt;/assets/</code>.
              </p>
            </div>

            {formData.logoPreview && (
              <div className={styles.logoPreview}>
                <span className={styles.label}>Preview</span>
                <img src={formData.logoPreview} alt="Logo preview" />
              </div>
            )}

            <div className={styles.actions}>
              <Button
                type="button"
                variant="secondary"
                onClick={resetForm}
                disabled={isSubmitting}
              >
                Reset
              </Button>
              <Button
                type="submit"
                variant="primary"
                isLoading={isSubmitting}
                disabled={!firebaseUser}
              >
                Seed Template
              </Button>
            </div>
          </form>
        </section>

        <section className={styles.panel}>
          <div className={styles.panelHeader}>
            <h2>Seeded Templates</h2>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => void loadTemplates()}
              disabled={!firebaseUser || isLoadingTemplates}
            >
              Refresh
            </Button>
          </div>

          {!firebaseUser && (
            <p className={styles.muted}>Connect Firebase to list templates.</p>
          )}

          {firebaseUser && isLoadingTemplates && (
            <p className={styles.muted}>Loading templates...</p>
          )}

          {firebaseUser && !isLoadingTemplates && sortedTemplates.length === 0 && (
            <p className={styles.muted}>No templates found.</p>
          )}

          {firebaseUser && !isLoadingTemplates && sortedTemplates.length > 0 && (
            <div className={styles.list}>
              {sortedTemplates.map(template => (
                <article key={template._docId} className={styles.listItem}>
                  <div className={styles.itemInfo}>
                    <h3>{template.name || template._docId}</h3>
                    <p className={styles.itemMeta}>
                      doc: <code>{template._docId}</code>
                    </p>
                    <p className={styles.itemMeta}>
                      ref: <code>{template.id}</code>
                    </p>
                  </div>
                  <div className={styles.itemActions}>
                    <Button
                      variant="danger"
                      size="sm"
                      onClick={() => void handleDelete(template._docId)}
                    >
                      Delete
                    </Button>
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState, use } from 'react';
import { useRouter } from 'next/navigation';
import { useJobStore } from '@/stores/job';
import { useJobWebSocket } from '@/hooks/useJobWebSocket';
import { authFetch } from '@/services/auth';
import { endpoints } from '@/lib/config';
import { PipelineTimeline } from '@/components/job/PipelineTimeline';
import { ClipGallery } from '@/components/job/ClipGallery';
import { Button } from '@/components/ui/Button';
import styles from './page.module.css';

interface JobDetailPageProps {
  params: Promise<{
    id: string;
  }>;
}

export default function JobDetailPage({ params }: JobDetailPageProps) {
  const router = useRouter();
  const { id } = use(params);
  const {
    job,
    isLoading,
    error: storeError,
    setJob,
    setError,
    setLoading,
    reset,
  } = useJobStore();

  // Local state for initial fetch status to handle 403/404 explicitly
  const [fetchStatus, setFetchStatus] = useState<
    'idle' | 'loading' | 'success' | 'error'
  >('idle');
  const [fetchError, setFetchError] = useState<{ code: number; message: string } | null>(
    null
  );

  // 1. REST First: Fetch job data
  useEffect(() => {
    // Clear previous job state before fetching new job
    reset();

    async function fetchJob() {
      setFetchStatus('loading');
      setLoading(true);
      try {
        const response = await authFetch(endpoints.jobs.get(id));

        if (!response.ok) {
          const status = response.status;
          if (status === 403) {
            throw { code: 403, message: 'This job does not belong to you.' };
          } else if (status === 404) {
            throw { code: 404, message: 'Job not found.' };
          } else {
            throw { code: status, message: 'Failed to load job.' };
          }
        }

        const data = await response.json();
        setJob(data);
        setFetchStatus('success');
      } catch (err: any) {
        console.error('Job fetch error:', err);
        const errorObj = err.code
          ? err
          : { code: 500, message: err.message || 'An error occurred' };
        setFetchError(errorObj);
        setError(errorObj.message);
        setFetchStatus('error');
      } finally {
        setLoading(false);
      }
    }

    fetchJob();
  }, [id, setJob, setError, setLoading, reset]);

  // 2. WebSocket: Connect ONLY if job exists and is active
  const shouldConnect =
    fetchStatus === 'success' &&
    job &&
    job.status !== 'completed' &&
    job.status !== 'failed';
  useJobWebSocket(shouldConnect ? id : '');

  if (fetchStatus === 'loading') {
    return (
      <div className={styles.loading}>
        <div className={styles.spinner} />
        <p>Loading job details...</p>
      </div>
    );
  }

  if (fetchStatus === 'error' && fetchError) {
    return (
      <div className={styles.errorContainer}>
        <div className={styles.errorCard}>
          <h2 className={styles.errorCode}>{fetchError.code}</h2>
          <p className={styles.errorMessage}>{fetchError.message}</p>
          <Button onClick={() => router.push('/dashboard/jobs')} variant="secondary">
            Back to Jobs
          </Button>
        </div>
      </div>
    );
  }

  if (!job) return null;

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <div className={styles.headerLeft}>
          <button
            onClick={() => router.push('/dashboard/jobs')}
            className={styles.backButton}
          >
